import { useState, useEffect } from 'react';
import { getUsers, updateUserRole } from '../api';
import TopBar, { LIGHT, DARK } from '../components/TopBar';

const ROLE_LABELS = { staff: '직원', manager: '매장관리자', owner: '대표자' };
const ROLE_COLORS = {
  staff: { bg: '#faeeda', color: '#854f0b' },
  manager: { bg: '#e1f5ee', color: '#0f6e56' },
  owner: { bg: '#eeedfe', color: '#534ab7' },
};

export default function Members({ dark, setDark }) {
  const c = dark ? DARK : LIGHT;
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => { fetchUsers(); }, []);

  const fetchUsers = () => {
    getUsers().then(res => setUsers(res.data)).finally(() => setLoading(false));
  };

  const handleEdit = (user) => {
    setEditUser(user);
    setForm({
      username: user.username || '',
      name: user.name || '',
      email: user.email || '',
      password: '',
      confirmPassword: '',
      phone: user.phone || '',
      address: user.address || '',
      addressDetail: user.address_detail || '',
      residentNumber: '',
      role: user.role || 'customer',
      is_adult: user.is_adult ? true : false,
    });
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUpdate = async () => {
    if (!form.username) { alert('아이디를 입력해주세요!'); return; }
    if (!form.name) { alert('이름을 입력해주세요!'); return; }
    if (!form.email) { alert('이메일을 입력해주세요!'); return; }
    setSubmitting(true);
    try {
      await API.put(`/users/${editUser.id}/edit`, {
        username: form.username,
        name: form.name,
        email: form.email,
        phone: form.phone,
        address: form.address,
        addressDetail: form.addressDetail,
        is_adult: form.is_adult,
      });
      alert('회원 정보가 수정됐어요! 😊');
      setForm({ ...emptyForm });
      setShowForm(false);
      setEditUser(null);
      fetchUsers();
    } catch (err) {
      alert('❌ ' + (err.response?.data?.error || '수정 실패!'));
    } finally {
      setSubmitting(false);
    }
  };

  const handleRoleChange = async (id, role) => {
    await updateUserRole(id, role);
    fetchUsers();
    alert('권한이 변경됐어요!');
  };

  const filtered = users.filter(u => u.name.includes(search) || u.email.includes(search));

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', background: c.bg, fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif' }}>
      <TopBar title="회원 관리" dark={dark} setDark={setDark}>
        <span style={{ fontSize: 13, color: c.textTertiary }}>총 {filtered.length}명</span>
      </TopBar>

      <div style={{ flex: 1, overflowY: 'auto', padding: 24 }}>
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="이름 또는 이메일 검색..."
          style={{ padding: '9px 12px', borderRadius: 8, border: `1.5px solid ${c.inputBorder}`, fontSize: 13, outline: 'none', width: 280, marginBottom: 16, background: c.inputBg, color: c.textPrimary }} />

        <div style={{ background: c.cardBg, borderRadius: 12, border: `1px solid ${c.cardBorder}`, overflow: 'hidden' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ background: c.metricBg }}>
                {['이름', '이메일', '연락처', '등급', '성인여부', '가입일', '권한 변경'].map(h => (
                  <th key={h} style={{ padding: '10px 16px', textAlign: 'left', fontSize: 12, color: c.textTertiary, fontWeight: 600 }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={7} style={{ padding: 24, textAlign: 'center', color: c.textTertiary }}>로딩 중...</td></tr>
              ) : filtered.length === 0 ? (
                <tr><td colSpan={7} style={{ padding: 24, textAlign: 'center', color: c.textTertiary }}>회원이 없어요</td></tr>
              ) : filtered.map(user => (
                <tr key={user.id} style={{ borderTop: `1px solid ${c.cardBorder}` }}>
                  <td style={{ padding: '12px 16px', fontSize: 13, fontWeight: 600, color: c.textPrimary }}>{user.name}</td>
                  <td style={{ padding: '12px 16px', fontSize: 13, color: c.textSecondary }}>{user.email}</td>
                  <td style={{ padding: '12px 16px', fontSize: 13, color: c.textTertiary }}>{user.phone || '-'}</td>
                  <td style={{ padding: '12px 16px' }}>
                    <span style={{ fontSize: 11, padding: '3px 10px', borderRadius: 20, fontWeight: 600, background: ROLE_COLORS[user.role]?.bg || '#eee', color: ROLE_COLORS[user.role]?.color || '#666' }}>
                      {ROLE_LABELS[user.role] || user.role}
                    </span>
                  </td>
                  <td style={{ padding: '12px 16px', fontSize: 13, color: user.is_adult ? '#009a58' : c.textTertiary }}>
                    {user.is_adult ? '✅ 성인' : '미성년'}
                  </td>
                  <td style={{ padding: '12px 16px', fontSize: 12, color: c.textTertiary }}>
                    {new Date(user.created_at).toLocaleDateString('ko-KR')}
                  </td>
                  <td style={{ padding: '12px 16px' }}>
                    <select value={user.role} onChange={e => handleRoleChange(user.id, e.target.value)}
                      style={{ padding: '5px 10px', borderRadius: 8, border: `1.5px solid ${c.inputBorder}`, fontSize: 12, outline: 'none', cursor: 'pointer', background: c.inputBg, color: c.textPrimary }}>
                      <option value="staff">직원</option>
                      <option value="manager">매장관리자</option>
                      <option value="owner">대표자</option>
                    </select>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
